function solve(nums: number[], k: number): number {
    if (nums.length === 1) {
        return 0;
    }

    // Sort the array to easily find min and max
    nums.sort((a, b) => a - b);

    // Try all possible subarrays to find the longest balanced subarray
    let maxLen = 1;
    let minRemovals = nums.length - 1; // Worst case: remove all but one

    for (let i = 0; i < nums.length; i++) {
        // Use a sliding window to find the longest valid subarray starting at i
        let j = i;
        while (j < nums.length) {
            // Check if the current subarray is balanced
            if (nums[j] <= nums[i] * k) {
                // Update the maximum length of balanced subarray
                maxLen = Math.max(maxLen, j - i + 1);
                j++;
            } else {
                break;
            }
        }
    }

    // The minimum number of elements to remove is total elements minus the length of the longest balanced subarray
    return nums.length - maxLen;
}

